import { prisma } from '@/lib/prisma';

// =============================================================================
// Types
// =============================================================================

export type PlanTier = 'free' | 'pro' | 'business';

export interface PlanLimits {
  /** Vídeos que o usuário pode criar por mês */
  videosPerMonth: number;
  /** Renders (queue jobs) que o usuário pode enfileirar por mês */
  rendersPerMonth: number;
  /** Storage em bytes */
  storageBytes: number;
  /** Storage em GB (derivado) */
  storageGb: number;
  /** Minutos de TTS por mês */
  ttsMinutesPerMonth: number;
  /** Duração máxima de cada vídeo em segundos */
  maxVideoDurationSeconds: number;
}

export interface PlanConfig {
  name: string;
  limits: PlanLimits;
}

// =============================================================================
// Canonical Plan Definitions
// =============================================================================

const FREE_STORAGE_GB = 1;
const PRO_STORAGE_GB = 50;
const BUSINESS_STORAGE_GB = 200;

export const PLANS: Record<PlanTier, PlanConfig> = {
  free: {
    name: 'Free',
    limits: {
      videosPerMonth: 1,
      rendersPerMonth: 5,
      storageBytes: 1024 * 1024 * 1024 * FREE_STORAGE_GB,
      storageGb: FREE_STORAGE_GB,
      ttsMinutesPerMonth: 5,
      maxVideoDurationSeconds: 300, // 5 min
    },
  },
  pro: {
    name: 'Pro',
    limits: {
      videosPerMonth: 10,
      rendersPerMonth: 100,
      storageBytes: 1024 * 1024 * 1024 * PRO_STORAGE_GB,
      storageGb: PRO_STORAGE_GB,
      ttsMinutesPerMonth: 60,
      maxVideoDurationSeconds: 1800, // 30 min
    },
  },
  business: {
    name: 'Business',
    limits: {
      videosPerMonth: 999999, // unlimited
      rendersPerMonth: 999999,
      storageBytes: 1024 * 1024 * 1024 * BUSINESS_STORAGE_GB,
      storageGb: BUSINESS_STORAGE_GB,
      ttsMinutesPerMonth: 9999,
      maxVideoDurationSeconds: 7200, // 2 hours
    },
  },
} as const;

// =============================================================================
// Derived Exports (para backward compat com feature-gate, webhook, etc.)
// =============================================================================

/** Mapa plano → limite de vídeos/mês (usado por feature-gate e webhook) */
export const PLAN_VIDEO_LIMITS: Record<PlanTier, number> = {
  free: PLANS.free.limits.videosPerMonth,
  pro: PLANS.pro.limits.videosPerMonth,
  business: PLANS.business.limits.videosPerMonth,
};

/** Mapa plano → storage em GB (usado por feature-gate) */
export const PLAN_STORAGE_LIMITS_GB: Record<PlanTier, number> = {
  free: PLANS.free.limits.storageGb,
  pro: PLANS.pro.limits.storageGb,
  business: PLANS.business.limits.storageGb,
};

/** Mapa plano → limites (formato usado por subscription API) */
export const PLAN_LIMITS_SUMMARY: Record<PlanTier, { videos: number; storage_gb: number; tts_minutes: number }> = {
  free: { videos: PLANS.free.limits.videosPerMonth, storage_gb: FREE_STORAGE_GB, tts_minutes: PLANS.free.limits.ttsMinutesPerMonth },
  pro: { videos: PLANS.pro.limits.videosPerMonth, storage_gb: PRO_STORAGE_GB, tts_minutes: PLANS.pro.limits.ttsMinutesPerMonth },
  business: { videos: PLANS.business.limits.videosPerMonth, storage_gb: BUSINESS_STORAGE_GB, tts_minutes: PLANS.business.limits.ttsMinutesPerMonth },
};

// =============================================================================
// Helpers
// =============================================================================

/** Valida se um tier é válido */
export function isValidPlanTier(tier: string): tier is PlanTier {
  return tier === 'free' || tier === 'pro' || tier === 'business';
}

/** Retorna o plano do usuário via Prisma (fallback: 'free') */
export async function getUserPlan(userId: string): Promise<PlanTier> {
  const user = await prisma.users.findUnique({
    where: { id: userId },
    select: { plan_tier: true },
  });
  const planTier = (user?.plan_tier as PlanTier | null) ?? 'free';
  return isValidPlanTier(planTier) ? planTier : 'free';
}

/** Verifica limite de renders ou storage via Prisma user_usage */
export async function checkLimit(
  userId: string,
  resource: 'renders' | 'storage',
  amount = 1
): Promise<{ allowed: boolean; reason?: string }> {
  const plan = await getUserPlan(userId);
  const limits = PLANS[plan].limits;

  const date = new Date();
  const currentMonth = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;

  const usage = await prisma.user_usage.findUnique({
    where: {
      userId_month: {
        userId,
        month: currentMonth,
      },
    },
  });

  if (resource === 'renders') {
    const currentRenders = usage?.rendersCount || 0;
    if (currentRenders + amount > limits.rendersPerMonth) {
      return { allowed: false, reason: `Monthly render limit reached (${limits.rendersPerMonth})` };
    }
  }

  if (resource === 'storage') {
    const currentStorage = Number(usage?.storageUsedBytes || 0);
    if (currentStorage + amount > limits.storageBytes) {
      return { allowed: false, reason: `Storage limit reached (${limits.storageGb}GB)` };
    }
  }

  return { allowed: true };
}
